CREATE TABLE `species` (
  `gbif_species_key` int(11) NOT NULL COMMENT 'GBIF (Global Biodiversity Information Facility) species identifier',
  `species_name` varchar(100) NOT NULL COMMENT 'Scientific name of the species',
  `common_name` varchar(100) DEFAULT NULL COMMENT 'Common English name',
  `iucn_red_list_category` varchar(10) DEFAULT NULL COMMENT 'IUCN Red List conservation status code',
  `body_mass_kg` decimal(10,3) DEFAULT NULL COMMENT 'Typical body mass in kilograms',
  `dietary_category` varchar(50) DEFAULT NULL COMMENT 'Primary dietary classification (Herbivore, Carnivore, Omnivore, Insectivore, Piscivore)',
  `uk_protection_status` varchar(255) DEFAULT NULL COMMENT 'UK legal protection status and relevant legislation',
  `habitat` varchar(100) DEFAULT NULL COMMENT 'Primary habitat types',
  `image_url` varchar(255) DEFAULT NULL COMMENT 'URL to species image (e.g., from Wikimedia Commons)',
  PRIMARY KEY (`gbif_species_key`),
  KEY `idx_species_name` (`species_name`),
  KEY `idx_dietary_category` (`dietary_category`),
  KEY `idx_iucn_category` (`iucn_red_list_category`)
);

set autocommit=0;
commit;
CREATE TABLE `observations` (
  `id` int(11) NOT NULL,
  `locality` varchar(255) DEFAULT NULL COMMENT 'Location name or description',
  `individual_count` int(11) DEFAULT NULL COMMENT 'Number of individuals observed',
  `latitude` decimal(10,6) DEFAULT NULL COMMENT 'Decimal latitude (WGS84)',
  `longitude` decimal(10,6) DEFAULT NULL COMMENT 'Decimal longitude (WGS84)',
  `gbif_species_key` int(11) DEFAULT NULL COMMENT 'GBIF species identifier - foreign key to SPECIES table',
  `observation_date` date DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_gbif_key` (`gbif_species_key`),
  KEY `idx_location` (`latitude`,`longitude`),
  CONSTRAINT `fk_species` FOREIGN KEY (`gbif_species_key`) REFERENCES `species` (`gbif_species_key`)
);

set autocommit=0;
commit;

